#!/usr/bin/env python3
import json, sys, subprocess

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    if tool != "Edit":
        return 0

    inp = ev.get("tool_input") or {}
    fpath = inp.get("file_path", "")
    if not fpath.endswith(".py"):
        return 0

    try:
        result = subprocess.run(
            ["python", "-m", "pyflakes", fpath],
            capture_output=True,
            text=True,
            timeout=5
        )
        if result.stdout or result.stderr:
            output = (result.stdout + result.stderr).strip()
            if output:
                print(f"Pyflakes found issues in {fpath}:", file=sys.stderr)
                print(output, file=sys.stderr)
                print("\nFIX EACH PYFLAKES ERROR ABOVE. Do not stop until fixed.", file=sys.stderr)
    except Exception:
        pass

    return 0

if __name__ == "__main__":
    sys.exit(main())
